import OpenSeadragon from 'https://cdn.jsdelivr.net/npm/openseadragon@6/+esm';
const el = document.createElement('div'); el.style.height = (data.height ?? 500) + 'px'; shadowRoot.appendChild(el);
const viewer = OpenSeadragon({ element: el, prefixUrl: 'https://cdn.jsdelivr.net/npm/openseadragon@6.0.2/build/openseadragon/images/', tileSources: data.tileSources, showNavigator: data.showNavigator ?? true, crossOriginPolicy: data.crossOriginPolicy ?? 'Anonymous' });

